class SecureTokenGenerator(hmacSecret: String) extends TokenGenerator {

  private val secureRandom = new SecureRandom()
  private val sessionStore: TrieMap[String, SessionToken] = TrieMap.empty
  private val apiKeyStore: TrieMap[String, ApiKey] = TrieMap.empty

  // Use SecureRandom instead of scala.util.Random for cryptographic security
  // Note: scala.util.Random.alphanumeric.take(32).mkString is NOT suitable for security tokens
  // as it uses a non-cryptographic PRNG. We use SecureRandom instead.

  private def generateSecureRandomString(length: Int): String = {
    val alphanumeric = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    val bytes = new Array[Byte](length)
    secureRandom.nextBytes(bytes)
    bytes.map(b => alphanumeric(Math.abs(b % alphanumeric.length))).mkString
  }

  private def generateSecureBytes(length: Int): Array[Byte] = {
    val bytes = new Array[Byte](length)
    secureRandom.nextBytes(bytes)
    bytes
  }

  private def hmacSign(data: String): String = {
    val mac = Mac.getInstance("HmacSHA256")
    val keySpec = new SecretKeySpec(hmacSecret.getBytes("UTF-8"), "HmacSHA256")
    mac.init(keySpec)
    val rawHmac = mac.doFinal(data.getBytes("UTF-8"))
    Base64.getUrlEncoder.withoutPadding().encodeToString(rawHmac)
  }

  private def generateSignedToken(payload: String): String = {
    val randomPart = generateSecureRandomString(32)
    val combined = s"$randomPart.$payload"
    val signature = hmacSign(combined)
    s"$combined.$signature"
  }

  private def verifySignature(token: String): Boolean = {
    val parts = token.split("\\.", 3)
    if (parts.length != 3) return false
    val data = s"${parts(0)}.${parts(1)}"
    val expectedSignature = hmacSign(data)
    constantTimeEquals(expectedSignature, parts(2))
  }

  // Constant-time comparison to prevent timing attacks
  private def constantTimeEquals(a: String, b: String): Boolean = {
    if (a.length != b.length) return false
    var result = 0
    for (i <- a.indices) {
      result |= a.charAt(i) ^ b.charAt(i)
    }
    result == 0
  }

  override def generateSessionToken(userId: String, ttlMinutes: Long = 30): SessionToken = {
    val now = Instant.now()
    val expiresAt = now.plus(Duration.ofMinutes(ttlMinutes))
    val timestamp = now.toEpochMilli.toString
    val token = generateSignedToken(s"session:$userId:$timestamp")

    val sessionToken = SessionToken(
      token = token,
      userId = userId,
      createdAt = now,
      expiresAt = expiresAt
    )

    sessionStore.put(token, sessionToken)
    sessionToken
  }

  override def generateApiKey(owner: String, permissions: Set[String] = Set.empty): ApiKey = {
    val keyBytes = generateSecureBytes(24)
    val secretBytes = generateSecureBytes(48)

    val key = s"ak_${Base64.getUrlEncoder.withoutPadding().encodeToString(keyBytes)}"
    val secret = Base64.getUrlEncoder.withoutPadding().encodeToString(secretBytes)

    // Store the HMAC of the secret, not the secret itself
    val hashedSecret = hmacSign(secret)

    val apiKey = ApiKey(
      key = key,
      secret = hashedSecret,
      owner = owner,
      createdAt = Instant.now(),
      permissions = permissions,
      active = true
    )

    apiKeyStore.put(key, apiKey)

    // Return the API key with the raw secret (only time it's available)
    apiKey.copy(secret = secret)
  }

  override def validateSessionToken(token: String): Option[SessionToken] = {
    if (!verifySignature(token)) {
      None
    } else {
      sessionStore.get(token).flatMap { session =>
        if (Instant.now().isBefore(session.expiresAt)) {
          Some(session)
        } else {
          sessionStore.remove(token)
          None
        }
      }
    }
  }

  override def validateApiKey(key: String, secret: String): Option[ApiKey] = {
    apiKeyStore.get(key).flatMap { storedKey =>
      if (storedKey.active && constantTimeEquals(hmacSign(secret), storedKey.secret)) {
        Some(storedKey)
      } else {
        None
      }
    }
  }

  override def revokeSessionToken(token: String): Boolean = {
    sessionStore.remove(token).isDefined
  }

  override def revokeApiKey(key: String): Boolean = {
    apiKeyStore.get(key) match {
      case Some(apiKey) =>
        apiKeyStore.put(key, apiKey.copy(active = false))
        true
      case None => false
    }
  }

  override def refreshSessionToken(token: String, ttlMinutes: Long = 30): Option[SessionToken] = {
    validateSessionToken(token).map { existingSession =>
      sessionStore.remove(token)
      generateSessionToken(existingSession.userId, ttlMinutes)
    }
  }

  override def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expiredTokens = sessionStore.filter { case (_, session) =>
      now.isAfter(session.expiresAt)
    }.keys.toList

    expiredTokens.foreach(sessionStore.remove)
    expiredTokens.size
  }

  def getActiveSessionCount: Int = {
    val now = Instant.now()
    sessionStore.count { case (_, session) => now.isBefore(session.expiresAt) }
  }

  def getActiveSessionsForUser(userId: String): List[SessionToken] = {
