// Rate limiter for token generation to prevent abuse
class TokenRateLimiter(maxRequestsPerMinute: Int) {
  private val requestCounts: TrieMap[String, (Int, Instant)] = TrieMap.empty

  def allowRequest(identifier: String): Boolean = {
    val now = Instant.now()
    requestCounts.get(identifier) match {
      case Some((count, windowStart)) =>
        if (Duration.between(windowStart, now).toMinutes >= 1) {
          requestCounts.put(identifier, (1, now))
          true
        } else if (count < maxRequestsPerMinute) {
          requestCounts.put(identifier, (count + 1, windowStart))
          true
        } else {
          false
        }
      case None =>
        requestCounts.put(identifier, (1, now))
        true
    }
  }
}

// Session management service combining token generation with rate limiting
class SessionManagementService(
  hmacSecret: String,
  maxTokenRequestsPerMinute: Int = 60,
  defaultSessionTtlMinutes: Long = 30
) {
  private val tokenGenerator = new SecureTokenGenerator(hmacSecret)
  private val rateLimiter = new TokenRateLimiter(maxTokenRequestsPerMinute)

  def createSession(userId: String, clientIp: String): Either[String, SessionToken] = {
    if (!rateLimiter.allowRequest(clientIp)) {
      Left("Rate limit exceeded. Please try again later.")
    } else {
      Right(tokenGenerator.generateSessionToken(userId, defaultSessionTtlMinutes))
    }
  }

  def validateSession(token: String): Either[String, SessionToken] = {
    tokenGenerator.validateSessionToken(token) match {
      case Some(session) => Right(session)
      case None => Left("Invalid or expired session token.")
    }
  }

  def refreshSession(token: String, clientIp: String): Either[String, SessionToken] = {
    if (!rateLimiter.allowRequest(clientIp)) {
      Left("Rate limit exceeded. Please try again later.")
    } else {
      tokenGenerator.refreshSessionToken(token, defaultSessionTtlMinutes) match {
        case Some(newSession) => Right(newSession)
        case None => Left("Unable to refresh session. Token may be invalid or expired.")
      }
    }
  }

  def createApiKey(owner: String, permissions: Set[String], clientIp: String): Either[String, ApiKey] = {
    if (!rateLimiter.allowRequest(clientIp)) {
      Left("Rate limit exceeded. Please try again later.")
    } else {
      Right(tokenGenerator.generateApiKey(owner, permissions))
    }
  }

  def validateApiKey(key: String, secret: String): Either[String, ApiKey] = {
    tokenGenerator.validateApiKey(key, secret) match {
      case Some(apiKey) => Right(apiKey)
      case None => Left("Invalid API key or secret.")
    }
  }

  def endSession(token: String): Boolean = tokenGenerator.revokeSessionToken(token)

  def endAllUserSessions(userId: String): Int = tokenGenerator.revokeAllSessionsForUser(userId)

  def deactivateApiKey(key: String): Boolean = tokenGenerator.revokeApiKey(key)

  def cleanup(): Int = tokenGenerator.cleanupExpiredSessions()

  def stats: Map[String, Int] = Map(
    "activeSessions" -> tokenGenerator.getActiveSessionCount
  )
}

